#!/usr/bin/env bash
# Deploy "who-attribution" change to the Vantaca Slack bot on the VPS.
#
# WHAT IT DOES:
#   1. Backs up index.mjs + vantaca-claude.mjs on the VPS (timestamped .bak).
#   2. Replaces index.mjs with a version that resolves real Slack names
#      (resolveUser via users.info) and passes audit {source,user,channel,thread}
#      into askVantaca, so audit rows show WHO made each request.
#   3. Patches vantaca-claude.mjs to store the AI answer text on the audit row
#      (answer field -> shown as "AI RESPONSE / ASSUMPTIONS" in Vantaca Controls).
#   4. node --check both files, then `systemctl restart vantaca-slack`.
#
# REQUIREMENTS (none of which exist in the Claude-Code-on-web sandbox):
#   - ssh client + ~/.ssh/vantaca_vps private key
#   - network egress to 134.209.126.217:22
#
# Payloads were syntax-validated (node --check / py_compile) before commit.
# If users.info returns a U0… id instead of a name, add the Slack `users:read`
# scope to the bot and reinstall, then re-run.
#
set -euo pipefail
ssh -i ~/.ssh/vantaca_vps root@134.209.126.217 'cd /root/vantaca-mcp/slack-bot && cp index.mjs index.mjs.bak.$(date +%s) && cp vantaca-claude.mjs vantaca-claude.mjs.bak.$(date +%s) && printf %s "" | base64 -d > index.mjs && printf %s "" | base64 -d > /tmp/pa.py && python3 /tmp/pa.py && node --check index.mjs && node --check vantaca-claude.mjs && echo SYNTAX_OK && systemctl restart vantaca-slack && sleep 2 && echo "slack:$(systemctl is-active vantaca-slack)"'
